#include<bits/stdc++.h>
using namespace std;
struct node
{
    char ch;
    bool flag;
};
int solve()//Return Code:-1 ERR 0 Yes 1 No
{
    int l;
    map<char,int> mp;
    string str;
    cin>>l>>str;
    int o;
    if(str=="O(1)")
    {
        o=0;
    }
    else
    {
        str=str.substr(4,str.length()-2);
        o=atoi(str.c_str());
    }
    int flag=0;
    int fcnt=0,breakflag=-1,ans=0,res=0;
    stack<node> stk;
    while(l--)
    {
        char ch,p;
        cin>>ch;
        if(ch=='F')
        {
            string x,y;
            char i,k;
            cin>>i>>x>>y;
            bool xisn=false,yisn=false;
            int nx,ny;
            if(x[0]=='n')
            {
                xisn=true;
            }
            else
            {
                nx=atoi(x.c_str());
            }
            if(y[0]=='n')
            {
                yisn=true;
            }
            else
            {
                ny=atoi(y.c_str());
            }
            if(i=='n')
            {
                flag=1;
            }
            if(flag)
            {
                continue;
            }
            if(mp[i]==1)
            {
                flag=1;
                continue;
            }
            mp[i]=1;
            fcnt++;
            if((xisn&&!yisn)||(!xisn&&!yisn&&nx>ny))
            {
                if(breakflag==-1)
                {
                    breakflag=fcnt;
                }
            }
            int flag=0;
            if(breakflag==-1&&(!xisn&&yisn))
            {
                flag=1;
                ans++;
            }
            stk.push((node){i,flag});
            res=max(res,ans);
        }
        else if(ch=='E')
        {
            if(fcnt==0)
            {
                flag=1;
            }
            if(flag==1)
            {
                continue;
            }
            ans-=stk.top().flag;
            if(breakflag==fcnt)
            {
                breakflag=-1;
            }
            fcnt--;
            mp[stk.top().ch]=0;
            stk.pop();
        }
    }
    if(flag==1||fcnt!=0)
    {
        return -1;
    }
    if(o==res)
    {
        return 0;
    }
    return 1;
}
int main()
{
    ios::sync_with_stdio(false);
    cin.tie(0);
    int t;
    cin>>t;
    while(t--)
    {
        int code=solve();
        if(code==-1)
        {
            cout<<"ERR\n";
        }
        else if(code==0)
        {
            cout<<"Yes\n";
        }
        else
        {
            cout<<"No\n";
        }
    }
    return 0;
}
